import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error(err));
    }, []);

    return (
        <header className="bg-white border-bottom sticky-top">
            <div className="container py-3">
                <div className="row align-items-center">

                    <div className="col-8 col-md-4">
                        <Link to="/">
                            <img src={logo} alt="Logo" style={{ minWidth: '200px', width: '100%', maxWidth: '300px' }} />
                        </Link>
                    </div>


                    <div className="col-4 d-md-none text-end">
                        <button className="navbar-toggler border p-2" type="button" data-bs-toggle="collapse" data-bs-target="#navContent">
                            <span className="navbar-toggler-icon"></span>
                        </button>
                    </div>


                    <div className="col-12 col-md-8 mt-3 mt-md-0 collapse d-md-block" id="navContent">
                        <div className="d-flex flex-column align-items-center align-items-md-end">


                            <div className="position-relative mb-3" style={{ width: '250px' }}>
                                <input
                                    className="form-control border-0 border-bottom rounded-0 shadow-none ps-0"
                                    type="text"
                                    placeholder="Rechercher"
                                    style={{ borderBottom: '2px solid #004a99' }}
                                />
                                <span className="position-absolute end-0 top-50 translate-middle-y">🔍</span>
                            </div>


                            <nav className="navbar navbar-expand-md p-0">
                                <div className="collapse navbar-collapse justify-content-end" id="navContent">
                                    <ul className="navbar-nav gap-3">
                                        {categories.map((cat, index) => (
                                            <li className="nav-item" key={cat.id || index}>
                                                <Link className="nav-link text-dark fw-bold px-2" to={`/category/${cat.id}`}>
                                                    {cat.name}
                                                </Link>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            </nav>
                        </div>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
